import { useEffect, useRef, useState } from "react";
import { clamp, ease } from "./helpers";

const TIMELINE = [
  {
    year: "1999",
    desc: "The first online shopping platform gained traction.",
    title: "Medium",
    sub: "Courier services",
  },
  {
    year: "2015",
    desc: "A social media platform introduced shoppable tags, where people could directly sell on the platform.",
    title: "Medium",
    sub: "Fleet operators",
  },
  {
    year: "2017",
    desc: "E-commerce platforms offered same-day delivery services to compete on speed and reach. Premium members.",
    title: "Medium",
    sub: "Fleet operators + delivery drivers",
  },
  {
    year: "2019",
    desc: "Food delivery platforms competed for speed promising delivery in 10–15 minutes from micro-fulfillment centers.",
    title: "Medium",
    sub: "Delivery Partners + Dark stores",
  },
  {
    year: "2021",
    desc: "Quick commerce gained popularity for providing sub-15 minute delivery for premium products.",
    title: "Medium",
    sub: "Delivery Partners + Dark stores",
  },
  {
    year: "2025",
    desc: "On-demand services (cleaning, cooking, etc) can be booked instantly.",
    title: "Medium",
    sub: "For everything instantly",
  },
];

function TimelineCard({ item }) {
  return (
    <div style={{
      minWidth: 260, maxWidth: 280, flexShrink: 0,
      background: "white",
      borderRadius: 16,
      overflow: "hidden",
      boxShadow: "0 8px 40px rgba(0,0,0,0.12), 0 2px 8px rgba(0,0,0,0.07)",
      border: "1px solid #efefef",
    }}>
      {/* Top: year + desc */}
      <div style={{ padding: "20px 20px 14px" }}>
        <div style={{
          display: "inline-block",
          background: "#e53e3e", color: "white",
          fontSize: 17, fontWeight: 800,
          padding: "4px 16px", borderRadius: 999,
          marginBottom: 14,
          fontFamily: "'Inter',sans-serif",
          letterSpacing: -0.3,
        }}>{item.year}</div>
        <p style={{
          fontSize: 13, color: "#444", lineHeight: 1.65,
          fontFamily: "'Inter',sans-serif", margin: 0,
        }}>{item.desc}</p>
      </div>

      {/* Divider */}
      <div style={{ height: 1, background: "#f0f0f0", margin: "0 20px" }} />

      {/* Medium + sub */}
      <div style={{ padding: "12px 20px 16px" }}>
        <p style={{
          fontSize: 15, fontWeight: 800, color: "#1a1a1a",
          fontFamily: "'Inter',sans-serif",
          textTransform: "uppercase", marginBottom: 2, letterSpacing: 0.2,
        }}>{item.title}</p>
        <p style={{
          fontSize: 12, color: "#888",
          fontFamily: "'Inter',sans-serif", lineHeight: 1.5, margin: 0,
        }}>{item.sub}</p>
      </div>
    </div>
  );
}

export default function WorkforceSection() {
  const sectionRef = useRef(null);
  const [progress, setProgress] = useState(0);

  useEffect(() => {
    const onScroll = () => {
      const el = sectionRef.current;
      if (!el) return;
      const scrolled = -el.getBoundingClientRect().top;
      const total = el.offsetHeight - window.innerHeight;
      setProgress(Math.max(0, Math.min(1, scrolled / (total * 0.95))));
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    onScroll();
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const headerT = ease(clamp(progress / 0.12, 0, 1));

  // All 6 cards form a rail. translateX goes from +100% (off right) → 0 as user scrolls.
  // Each card has a slight stagger but they move together as a train.
  // railShift: 0 = all cards fully right of viewport, 1 = rail settled into view
  const railShift = ease(clamp((progress - 0.10) / 0.75, 0, 1));

  // Individual card stagger for the entrance: each card slightly behind the previous
  const cardEntrance = (i) => ease(clamp((progress - 0.10 - i * 0.04) / 0.25, 0, 1));

  return (
    <div ref={sectionRef} style={{ height: "400vh", position: "relative" }}>
      <div style={{
        position: "sticky", top: 0, height: "100vh",
        overflow: "hidden",
        display: "flex", flexDirection: "column",
        background: "#fff",
        justifyContent: "center",
      }}>

        {/* ── Header ── */}
        <div style={{
          padding: "0 8vw",
          textAlign: "center",
          opacity: headerT,
          transform: `translateY(${(1 - headerT) * 30}px)`,
          marginBottom: 48,
        }}>
          <h2 style={{
            fontFamily: "'Playfair Display','Georgia',serif",
            fontSize: "clamp(42px,7vw,100px)",
            fontWeight: 900, color: "#e53e3e",
            lineHeight: 1.05, margin: "0 0 20px",
          }}>
            The Workforce<br />Behind Every Order
          </h2>
          <p style={{
            fontSize: "clamp(14px,1.15vw,18px)", color: "#444",
            lineHeight: 1.75, maxWidth: 780,
            margin: "0 auto 10px",
          }}>
            India's doorstep economy operates at the intersection of logistics,
            technology, and human workforce. But that wasn't the case 15 years ago.
            Let's look at how the gig economy evolved with various business models
            over the last 3 decades.
          </p>
          <p style={{ fontSize: 13, color: "#aaa", fontStyle: "italic", margin: 0 }}>
            Sources:{" "}
            <span style={{ textDecoration: "underline", cursor: "pointer" }}>Kearney</span>{" "}
            <span style={{ textDecoration: "underline", cursor: "pointer" }}>Young Urban Project</span>{" "}
            <span style={{ textDecoration: "underline", cursor: "pointer" }}>Shiproket</span>
          </p>
        </div>

        {/* ── Cards rail — slides in from right ── */}
        <div style={{
          width: "100%",
          overflow: "visible",
          paddingLeft: "6vw",
        }}>
          <div style={{
            display: "flex",
            gap: 20,
            // The whole rail translates from off-screen right toward 0
            transform: `translateX(${(1 - railShift) * 80}vw)`,
            willChange: "transform",
          }}>
            {TIMELINE.map((item, i) => (
              <div
                key={item.year}
                style={{
                  opacity: cardEntrance(i),
                  transform: `translateX(${(1 - cardEntrance(i)) * 60}px)`,
                  willChange: "transform, opacity",
                }}
              >
                <TimelineCard item={item} />
              </div>
            ))}
          </div>
        </div>

      </div>
    </div>
  );
}
